const m = $input.first().json;
let subject = m.subject || m.Subject || '(no subject)';
const from = m.from?.text || m.From || '';
const bodyRaw = (m.text || m.snippet || '');
const snippet = bodyRaw.substring(0, 500).replace(/\n/g, ' ').replace(/"/g, "'");

// Strip 'monday.com' (case-insensitive) and trim leftover whitespace/dashes
subject = subject.replace(/monday\.com/gi, '').replace(/\s+/g, ' ').replace(/^[\s\-:]+|[\s\-:]+$/g, '').trim();
if (!subject) subject = '(no subject)';

// Parse due date from body.
let dueDate = '';
const isoMatch = bodyRaw.match(/due\s*:?\s*(\d{4})-(\d{1,2})-(\d{1,2})(?!\d)/i);
const dmyMatch = bodyRaw.match(/due\s*:?\s*(\d{1,2})[\/\-\.](\d{1,2})[\/\-\.](\d{2,4})(?!\d)/i);
if (isoMatch) {
  const yyyy = isoMatch[1];
  const mm = isoMatch[2].padStart(2, '0');
  const dd = isoMatch[3].padStart(2, '0');
  dueDate = `${yyyy}-${mm}-${dd}`;
} else if (dmyMatch) {
  const dd = dmyMatch[1].padStart(2, '0');
  const mm = dmyMatch[2].padStart(2, '0');
  let year = dmyMatch[3];
  if (year.length === 2) {
    const n = parseInt(year, 10);
    year = (n < 70 ? 2000 + n : 1900 + n).toString();
  }
  dueDate = `${year}-${mm}-${dd}`;
}

// Parse priority from body. Supported: priority: low | medium | high | critical
// Also accepts shorthand: p: high, prio: low, !high, !critical
let priority = '';
const prioMap = {
  low: 'Low',
  l: 'Low',
  medium: 'Medium',
  med: 'Medium',
  m: 'Medium',
  high: 'High',
  h: 'High',
  critical: 'Critical',
  crit: 'Critical',
  urgent: 'Critical',
  c: 'Critical'
};
const prioMatch = bodyRaw.match(/(?:priority|prio|p)\s*:?\s*(low|medium|med|high|critical|crit|urgent|[lmhc])\b/i) || bodyRaw.match(/!(low|medium|med|high|critical|crit|urgent|[lmhc])\b/i);
if (prioMatch) {
  const key = prioMatch[1].toLowerCase();
  priority = prioMap[key] || '';
}

return [{ json: { name: subject.substring(0, 200), notes: `From: ${from}\n\n${snippet}`, messageId: m.id || '', dueDate, priority } }];

